contracts/KeelToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

contract KeelToken is ERC20, ERC20Burnable, AccessControl {

    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    bytes32 public constant LEDGER_ROLE = keccak256("LEDGER_ROLE");

    uint256 public monthlyIssuanceCap = 100 * 10 ** 18;

    mapping(bytes32 => uint256) public monthlyMinted;

    event TokensMinted(address indexed to, uint256 amount, uint256 year, uint256 month);
    event TokensBurnedForUsage(address indexed member, uint256 amount, bytes32 tripId);
    event MonthlyCapUpdated(uint256 newCap);

    constructor(address admin) ERC20("Keel Token", "KEEL") {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(MINTER_ROLE, admin);
        _grantRole(LEDGER_ROLE, admin);
    }

    function mintMonthlyAllocation(
        address member,
        uint256 amount,
        uint256 year,
        uint256 month
    ) external onlyRole(MINTER_ROLE) {
        bytes32 key = keccak256(abi.encodePacked(member, year, month));
        require(
            monthlyMinted[key] + amount <= monthlyIssuanceCap,
            "KeelToken: exceeds monthly cap"
        );
        monthlyMinted[key] += amount;
        _mint(member, amount);
        emit TokensMinted(member, amount, year, month);
    }

    function burnForUsage(
        address member,
        uint256 amount,
        bytes32 tripId
    ) external onlyRole(LEDGER_ROLE) {
        _burn(member, amount);
        emit TokensBurnedForUsage(member, amount, tripId);
    }

    function setMonthlyIssuanceCap(uint256 newCap)
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
    {
        monthlyIssuanceCap = newCap;
        emit MonthlyCapUpdated(newCap);
    }
}

contracts/KeelUsageLedger.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./KeelToken.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

contract KeelUsageLedger is AccessControl {

    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");

    KeelToken public keelToken;

    uint256 public baseRatePerHour = 1 * 10 ** 18;
    uint256 public eveningMultiplier = 140;
    uint256 public weekendMultiplier = 110;
    uint256 public holidayMultiplier = 125;
    uint256 public eveningStartHour = 18;

    struct TripRecord {
        bytes32 tripId;
        address member;
        uint256 startTimestamp;
        uint256 endTimestamp;
        uint256 dayHours;
        uint256 eveningHours;
        bool isWeekend;
        bool isHoliday;
        uint256 rawHours;
        uint256 trueUsageUnits;
        uint256 tokensBurned;
        bool settled;
    }

    mapping(bytes32 => TripRecord) public trips;
    bytes32[] public tripIds;

    event TripLogged(
        bytes32 indexed tripId,
        address indexed member,
        uint256 rawHours,
        uint256 trueUsageUnits,
        uint256 tokensBurned
    );

    constructor(address admin, address keelTokenAddress) {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(OPERATOR_ROLE, admin);
        keelToken = KeelToken(keelTokenAddress);
    }

    function logAndSettle(
        address member,
        uint256 startTs,
        uint256 endTs,
        bool isWeekend,
        bool isHoliday
    ) external onlyRole(OPERATOR_ROLE) returns (bytes32 tripId) {

        require(endTs > startTs, "KeelUsageLedger: invalid time range");

        tripId = keccak256(
            abi.encodePacked(member, startTs, endTs, block.timestamp)
        );
        require(!trips[tripId].settled, "KeelUsageLedger: already settled");

        (uint256 dayHours, uint256 eveningHours) = _splitHours(startTs, endTs);
        uint256 rawHours = dayHours + eveningHours;
        uint256 trueUsage = _calculateUsage(dayHours, eveningHours, isWeekend, isHoliday);
        uint256 tokenAmount = (trueUsage * baseRatePerHour) / 100;

        trips[tripId] = TripRecord({
            tripId: tripId,
            member: member,
            startTimestamp: startTs,
            endTimestamp: endTs,
            dayHours: dayHours,
            eveningHours: eveningHours,
            isWeekend: isWeekend,
            isHoliday: isHoliday,
            rawHours: rawHours,
            trueUsageUnits: trueUsage,
            tokensBurned: tokenAmount,
            settled: true
        });

        tripIds.push(tripId);
        keelToken.burnForUsage(member, tokenAmount, tripId);
        emit TripLogged(tripId, member, rawHours, trueUsage, tokenAmount);
        return tripId;
    }

    function _splitHours(uint256 startTs, uint256 endTs)
        internal
        view
        returns (uint256 dayHours, uint256 eveningHours)
    {
        uint256 cursor = startTs;
        dayHours = 0;
        eveningHours = 0;
        while (cursor < endTs) {
            uint256 hourOfDay = (cursor % 86400) / 3600;
            uint256 nextHour = cursor + 3600 - (cursor % 3600);
            if (nextHour > endTs) nextHour = endTs;
            uint256 segmentSeconds = nextHour - cursor;
            uint256 segmentHours = segmentSeconds / 3600;
            if (hourOfDay >= eveningStartHour) {
                eveningHours += segmentHours;
            } else {
                dayHours += segmentHours;
            }
            cursor = nextHour;
        }
    }

    function _calculateUsage(
        uint256 dayHours,
        uint256 eveningHours,
        bool isWeekend,
        bool isHoliday
    ) internal view returns (uint256 trueUsage) {
        uint256 dayUsage = dayHours * 100;
        uint256 eveningUsage = eveningHours * eveningMultiplier;
        uint256 totalUsage = dayUsage + eveningUsage;
        if (isWeekend) {
            totalUsage = (totalUsage * weekendMultiplier) / 100;
        }
        if (isHoliday) {
            totalUsage = (totalUsage * holidayMultiplier) / 100;
        }
        return totalUsage;
    }

    function getAllTripIds() external view returns (bytes32[] memory) {
        return tripIds;
    }

    function updateMultipliers(
        uint256 evening,
        uint256 weekend,
        uint256 holiday
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        eveningMultiplier = evening;
        weekendMultiplier = weekend;
        holidayMultiplier = holiday;
    }

    function updateBaseRate(uint256 newRate)
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
    {
        baseRatePerHour = newRate;
    }
}

